transform_js:
var total=rawData.rows.reduce(function(s,r){return s+r.n;},0);
var data=[];
var xOff=0;
var rowGroups={};
rawData.rows.forEach(function(r){if(!rowGroups[r.r])rowGroups[r.r]=[];rowGroups[r.r].push(r);});
Object.keys(rowGroups).forEach(function(rk){
  var grp=rowGroups[rk];
  var grpTotal=grp.reduce(function(s,r){return s+r.n;},0);
  var w=grpTotal/total*100;
  var yOff=0;
  grp.forEach(function(r){
    var h=r.n/grpTotal*100;
    data.push({value:[xOff,yOff,w,h],name:rk+' / '+r.c,count:r.n});
    yOff+=h;
  });
  xOff+=w;
});
transformedData=data;
